    }

    // ── Derived values ────────────────────────────────────────────────────────
    const tabDone: Record<Tab, boolean> = {
        details: validateDetails(),
        reward: validateReward(),
        tasks: validateTasks(),
        preview: false,
    }

    const tabValid: Record<Tab, boolean> = {
