        setTab(tab === targetTab ? null : targetTab)
    }

    // ─────────────────────────────────────────────────────────────────────────
    if (isEditMode && editLoading) {
        return (
            <div style={{ padding: "40px", textAlign: "center", color: "var(--fg-muted)" }}>
                Loading quest…
            </div>
