                        <span>🤖</span>
                        <span style={{ flex: 1 }}>
                            Add the <strong>ClawQuest bot</strong> to your server to enable join verification.
                        </span>
                        <Button size="sm" onClick={async (e) => {
                            e.stopPropagation()
